try {
  // Get file signature for validation
  const signature = bufferData.slice(0, 8).toString('hex').toUpperCase();
  const signatureString = bufferData.slice(0, 4).toString();

  console.log('File info:', {
    originalSize: inputData.json.headers['content-length'],
    bufferSize: bufferData.length,
    contentType: contentType,
    detectedType: fileType,
