    signature: signature,
    isValidPDF: signatureString === '%PDF',
    isValidImage: ['FFD8FF', '89504E47', '47494638', '424D'].some(sig => signature.startsWith(sig))
  });

  // Upload to Azure Blob Storage
  const response = await axios.put(uploadUrl, bufferData, {
    headers: {
      'x-ms-blob-type': 'BlockBlob',
      'Content-Type': contentType,
      'Content-Length': bufferData.length
    },
