               true
    }
  }];

} catch (error) {
  return [{
    json: {
      error: "❌ Failed to upload to Azure Blob Storage",
      message: error.message,
      details: error.response?.data || error.toString(),
      status: error.response?.status,
      debugInfo: {
        contentType: contentType,
        detectedType: fileType,
        originalSize: inputData.json.headers['content-length'],
        binaryDataType: typeof binaryDataObject,
        binaryDataKeys: binaryDataObject ? Object.keys(binaryDataObject) : null,
        bufferCreated: !!bufferData,
        bufferSize: bufferData ? bufferData.length : 0
      }
    }
  }];
}

