const guestInfo = $input.first().json.body.userSession.api.POST.guestinfo;
// Example: "Adarsh Sharma, 9643393874, 29-07-2025"

const values = guestInfo.split(',').map(value => value.trim());

const name = values[0];
const totalguests = values[1];
let phoneNumber = values[2];
const checkindate = values[3];
const checkoutdate = values[4];

// Add +91 if phone number has exactly 10 digits
if (phoneNumber.length === 10) {
  phoneNumber = '91' + phoneNumber;
}
const timestamp = Date.now();
const randomNum = Math.floor(Math.random() * 1000).toString().padStart(3, '0');
const uniqueId = `CHK${timestamp}${randomNum}`;
// Return as output object
return [
  {
    json: {
      name,
      totalguests,
      phoneNumber,
      checkindate,
      checkoutdate,
      uniqueId,
    }
  }
];

const output = [];

for (const item of $input.all()) {
  const mimeType = item.json.mime_type;

  // Check for valid Excel mime types
  if (
    mimeType === 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' ||
    mimeType === 'application/vnd.ms-excel'
  ) {
    // Add custom field and push to output
    const json = {
      ...item.json,
      myNewField: 1,
    };

    output.push({ json });
  }
  // If mime type is not valid, skip (do not push to output)
}

return output;

// Find the record with the most recent Check_In_Date
const dataArray = $('Code17').first().json.data;
const mostRecentCheckIn = dataArray.reduce((latest, current) => {
  const latestDate = new Date(latest.Check_In_Date);
  const currentDate = new Date(current.Check_In_Date);
  return currentDate > latestDate ? current : latest;
});

// Extract document URLs from the most recent check-in
const documentUrls = mostRecentCheckIn.Document_URL 
  ? mostRecentCheckIn.Document_URL.split(',').map(url => url.trim()).filter(url => url)
  : [];

const guestData = $input.first().json;
const webhookData = $('Webhook').first().json.body;

// Helper function to determine if file is PDF or image and get appropriate message structure
const getMessageStructure = (url, phoneNumber, caption) => {
  const extension = url.split('.').pop().toLowerCase().split('?')[0];

  const baseMessage = {
    messaging_product: 'whatsapp',
    recipient_type: 'individual',
    to: phoneNumber
  };

  if (extension === 'pdf') {
    return {
      ...baseMessage,
      type: 'document',
      document: {
        link: url,
        caption: caption,
        filename: `document_${Date.now()}.pdf`
      }
    };
  } else {
    return {
      ...baseMessage,
      type: 'image',
      image: {
        link: url,
        caption: caption
      }
    };
  }
};

// Generate the output array with dynamic message structures
return documentUrls.map((url, index) => {
  const caption = `📄 Document ${index + 1} from ${guestData.Name}`;
  const message = getMessageStructure(url, webhookData.userSession.userPhoneNumber, caption);

  return {
    json: {
      message: message,
      phone: webhookData.userSession.userPhoneNumber,
      business_phone_number_id: 606239485906302,
      access_token: webhookData.userSession.accessToken,
      tenant_id: guestData['Tenant ID'],
      custom: true
    }
  };
});

// N8N Code Node to calculate notification time and check-in status
const processedItems = [];
const today = new Date();
today.setHours(0, 0, 0, 0); // Set to start of today for accurate comparison

for (const item of $input.all()) {
  const data = item.json;

  let checkInDate;
  let notificationTime;
  let checkInStatus;
  let daysDifference;

  try {
    // Handle different date formats
    if (typeof data["Check-In Date"] === 'string' && data["Check-In Date"].trim() !== '') {
      // Handle DD-MM-YYYY format like "31-07-2025"
      const dateStr = data["Check-In Date"].trim();
      if (dateStr.includes('-') && dateStr.split('-').length === 3) {
        const [day, month, year] = dateStr.split('-');
        // Convert to YYYY-MM-DD format for JavaScript Date constructor
        checkInDate = new Date(`${year}-${month.padStart(2, '0')}-${day.padStart(2, '0')}`);
      } else {
        // Other string formats like "2025-07-22"
        checkInDate = new Date(data["Check-In Date"]);
      }
    } else if (typeof data["Check-In Date"] === 'number') {
      // Excel serial number format (days since 1900-01-01, with leap year bug)
      // Formula: (serial - 25569) * 86400000 to convert to JavaScript timestamp
      const excelSerialDate = data["Check-In Date"];
      checkInDate = new Date((excelSerialDate - 25569) * 86400000);
    } else {
      // Skip processing if Check-In Date is empty or invalid
      if (!data["Check-In Date"] || data["Check-In Date"].toString().trim() === '') {
        throw new Error('Check-In Date is empty');
      }
      throw new Error('Invalid date format');
    }

    // Validate the date
    if (isNaN(checkInDate.getTime())) {
      throw new Error('Invalid date');
    }

    // Set check-in date to start of day for accurate comparison
    const checkInDateOnly = new Date(checkInDate);
    checkInDateOnly.setHours(0, 0, 0, 0);

    // Calculate days difference (positive = future, negative = past, 0 = today)
    daysDifference = Math.ceil((checkInDateOnly - today) / (1000 * 60 * 60 * 24));

    // Determine status
    if (daysDifference > 0) {
      checkInStatus = "FUTURE"; // Check-in date is ahead
    } else if (daysDifference === 0) {
      checkInStatus = "TODAY"; // Check-in date is today
    } else {
      checkInStatus = "PAST"; // Check-in date has passed
    }

    // Set time to 12:00 PM (noon) on check-in date
    const noonCheckIn = new Date(checkInDate);
    noonCheckIn.setHours(12, 0, 0, 0);

    // Calculate 24 hours before (which is 12:00 PM the day before)
    notificationTime = new Date(noonCheckIn.getTime() - (24 * 60 * 60 * 1000));

    // Add the calculated notification time and status to the data
    const processedItem = {
      ...data,
      "Notification_Time": notificationTime.toISOString(),
      "Notification_Time_Local": notificationTime.toLocaleString('en-IN', {
        timeZone: 'Asia/Kolkata',
        year: 'numeric',
        month: '2-digit',
        day: '2-digit'
      }),
      "Check-In Date Parsed": checkInDate.toLocaleString('en-IN', {
        timeZone: 'Asia/Kolkata',
        year: 'numeric',
        month: '2-digit',
        day: '2-digit'
      }),
      "Check_In_Status": checkInStatus,
      "Days_Until_CheckIn": daysDifference,
      "Is_Past_CheckIn": daysDifference < 0,
      "Is_Today_CheckIn": daysDifference === 0,
      "Is_Future_CheckIn": daysDifference > 0
    };

    processedItems.push({ json: processedItem });

  } catch (error) {
    // Handle invalid dates gracefully
    const processedItem = {
      ...data,
      "Notification_Time": null,
      "Notification_Time_Local": null,
      "Check-In Date Parsed": "Invalid Date",
      "Check_In_Status": "ERROR",
      "Days_Until_CheckIn": null,
      "Is_Past_CheckIn": null,
      "Is_Today_CheckIn": null,
      "Is_Future_CheckIn": null,
      "Error": `Failed to parse date: ${data["Check-In Date"]}`
    };

    processedItems.push({ json: processedItem });
  }
}

return processedItems;

const d = new Date($input.first().json.currentDate);
const day = String(d.getDate()).padStart(2, '0');
const month = String(d.getMonth() + 1).padStart(2, '0');
const year = d.getFullYear();
const formattedDate = `${day}/${month}/${year}`;

return [
  {
    json: {
      formattedDate
    }
  }
];

