    } else if (binaryObject?.data) {
      console.log('Using direct data property');
      if (Buffer.isBuffer(binaryObject.data)) {
        qrImageBuffer = binaryObject.data;
      } else if (typeof binaryObject.data === 'string') {
        // If it's base64 string
        qrImageBuffer = Buffer.from(binaryObject.data, 'base64');
      } else {
        qrImageBuffer = Buffer.from(binaryObject.data);
      }
      binaryFound = true;
    } else if (Buffer.isBuffer(binaryObject)) {
      console.log('Binary object is already a buffer');
      qrImageBuffer = binaryObject;
      binaryFound = true;
