const axios = require('axios');

// 🔐 Azure Document Intelligence Config
const docIntelligenceKey = "f1ecbfcb87c84851bc85735f3694696c"; // Your Document Intelligence key
const docIntelligenceEndpoint = "https://zestayocr.cognitiveservices.azure.com/"; // Your Document Intelligence endpoint

// 📦 Azure Blob File Config
const account = "pdffornurenai";
const container = "pdf";

try {
  // 📲 Get phone number and build file path
  const phoneNumber = $('Webhook').first().json.body.userSession.userPhoneNumber;
  const uniqueId = Date.now();
  const fileName = `document_${uniqueId}.jpg`;
  const blobPath = `${phoneNumber}/${fileName}`;

  // 🔗 Full Azure Blob URL
  const imageUrl = $input.first().json.blobUrl;

  console.log(`Processing image with Document Intelligence: ${imageUrl}`);

  // Step 1: Submit document for analysis using the general document model
  const analyzeResponse = await axios.post(
    `${docIntelligenceEndpoint}/formrecognizer/documentModels/prebuilt-document:analyze?api-version=2023-07-31`,
    { urlSource: imageUrl },
    {
      headers: {
        'Ocp-Apim-Subscription-Key': docIntelligenceKey,
        'Content-Type': 'application/json'
      },
      timeout: 30000
    }
  );

  // Get the operation location from response headers
  const operationLocation = analyzeResponse.headers['operation-location'];
  if (!operationLocation) {
    throw new Error('No operation location returned from Document Intelligence');
  }

  // Step 2: Poll for results
  let resultResponse;
  let attempts = 0;
  const maxAttempts = 30; // 30 attempts with 2 second intervals = 1 minute max

  while (attempts < maxAttempts) {
    await new Promise(resolve => setTimeout(resolve, 2000)); // Wait 2 seconds

    resultResponse = await axios.get(operationLocation, {
      headers: {
        'Ocp-Apim-Subscription-Key': docIntelligenceKey
      }
    });

    if (resultResponse.data.status === 'succeeded') {
      break;
    } else if (resultResponse.data.status === 'failed') {
      throw new Error(`Document analysis failed: ${resultResponse.data.error?.message || 'Unknown error'}`);
    }

    attempts++;
  }

  if (resultResponse.data.status !== 'succeeded') {
    throw new Error('Document analysis timed out');
  }

  // Step 3: Extract text from the results
  let extractedText = '';
  const analysisResult = resultResponse.data.analyzeResult;

  if (analysisResult && analysisResult.content) {
    extractedText = analysisResult.content;
  } else if (analysisResult && analysisResult.pages) {
    // Fallback: extract from pages if content is not available
    extractedText = analysisResult.pages
      .map(page => {
        if (page.lines) {
          return page.lines.map(line => line.content).join(' ');
        }
        return '';
      })
      .join(' ');
  }

  // 🔍 Advanced document type detection
  function detectDocumentType(text) {
    if (!text) return "unknown";
    const lowerText = text.toLowerCase();
    const normalizedText = text.replace(/\s+/g, ' ').trim();

    // Aadhaar Card Detection (multiple patterns)
    if (
      lowerText.includes("aadhaar") || 
      lowerText.includes("unique identification") || 
      lowerText.includes("government of india") && lowerText.includes("uid") ||
      /\b\d{4}\s\d{4}\s\d{4}\b/.test(normalizedText) || // Aadhaar number pattern
      lowerText.includes("uidai") ||
      lowerText.includes("unique identity") ||
      lowerText.includes("आधार") ||
      lowerText.includes("मेरा आधार") ||
      lowerText.includes("भारत सरकार")
    ) {
      return "aadhaar";
    }

    // Driving License Detection
    if (
      lowerText.includes("driving license") || 
      lowerText.includes("licence to drive") ||
      lowerText.includes("dl no") ||
      lowerText.includes("transport department") ||
      /dl\s*\d{2}\s*\d{8,}/i.test(text) || // DL number pattern
      lowerText.includes("motor vehicle") ||
      lowerText.includes("auth to drive") ||
      lowerText.includes("licence no") ||
      lowerText.includes("vehicles throughout india")
    ) {
      return "driving_license";
    }

    // PAN Card Detection
    if (
      lowerText.includes("income tax") || 
      lowerText.includes("pan") ||
      /[a-z]{5}[0-9]{4}[a-z]{1}/i.test(text) || // PAN pattern
      lowerText.includes("permanent account number") ||
      lowerText.includes("tax payer")
    ) {
      return "pan";
    }

    // Passport Detection
    if (
      lowerText.includes("passport") || 
      lowerText.includes("republic of india") ||
      lowerText.includes("ministry of external affairs") ||
      lowerText.includes("भारत गणराज्य") ||
      lowerText.includes("विदेश मंत्रालय") ||
      /[a-z]\d{7}/i.test(text) || // Passport number pattern
      lowerText.includes("place of birth") ||
      lowerText.includes("जन्म स्थान") ||
      lowerText.includes("date of expiry") ||
      lowerText.includes("given name") ||
      lowerText.includes("surname") ||
      lowerText.includes("nationality") ||
      lowerText.includes("राष्ट्रीयता")
    ) {
      return "passport";
    }

    // Voter ID Detection (Election Card)
    if (
      lowerText.includes("voter") || 
      lowerText.includes("election commission") ||
      lowerText.includes("elector") ||
      lowerText.includes("epic") ||
      lowerText.includes("मतदाता") ||
      lowerText.includes("निर्वाचन आयोग") ||
      lowerText.includes("चुनाव आयोग") ||
      lowerText.includes("electoral photo identity") ||
      lowerText.includes("electors photo identity") ||
      /[a-z]{3}\d{7}/i.test(text) || // Voter ID pattern
      lowerText.includes("constituency") ||
      lowerText.includes("निर्वाचन क्षेत्र") ||
      lowerText.includes("assembly constituency") ||
      lowerText.includes("part no") ||
      lowerText.includes("serial no")
    ) {
      return "voter_id";
    }

    return "unknown";
  }

  // 📝 Extract specific information based on document type
  function extractDocumentInfo(text, docType) {
    const info = {
      holderName: null,
      fatherName: null,
      documentNumber: null,
      dateOfBirth: null,
      address: null,
      gender: null,
      issueDate: null,
      validityDate: null,
      placeOfBirth: null,
      constituency: null
    };

    // Helper function to clean extracted text
    function cleanText(str) {
      return str ? str.replace(/\n/g, ' ').replace(/\s+/g, ' ').trim() : null;
    }

    // Helper function to extract name with multiple fallback patterns
    function extractNameMultiplePatterns(patterns) {
      for (const pattern of patterns) {
        const match = text.match(pattern);
        if (match && match[1] && match[1].trim().length > 1) {
          return cleanText(match[1]);
        }
      }
      return null;
    }

    if (docType === "aadhaar") {
      // Enhanced name extraction for Aadhaar with Hindi and English patterns
      info.holderName = extractNameMultiplePatterns([
        // Pattern for "आदर्श शर्मा Adarsh Sharma" format
        /([A-Z][a-z]+(?:\s+[A-Z][a-z]+)*)\s+जन्म तिथि/i,
        /([A-Z][a-z]+(?:\s+[A-Z][a-z]+)*)\s+DOB/i,
        // Pattern for Hindi name followed by English name
        /[^\w\s]+\s*([A-Z][a-z]+(?:\s+[A-Z][a-z]+)*)\s+([A-Z][a-z]+(?:\s+[A-Z][a-z]+)*)/i,
        // Standard name patterns
        /(?:Name|नाम)[:\s]*([A-Za-z\s]+?)(?=\s+(?:जन्म|DOB|Date of Birth|Gender|Male|Female))/i,
        // Pattern before DOB/Gender
        /([A-Z][a-z]+(?:\s+[A-Z][a-z]+)*)\s+(?:जन्म तिथि|DOB)[:\s]/i,
        // Pattern for standalone English name before demographics
        /([A-Z][a-z]+(?:\s+[A-Z][a-z]+)*)\s+(?:\d{2}\/\d{2}\/\d{4}|Male|Female|पुरुष|महिला)/i
      ]);

      // Father's name patterns for Aadhaar
      info.fatherName = extractNameMultiplePatterns([
        /(?:Father|पिता|S\/O|Son of)[:\s]*([A-Za-z\s]+?)(?=\s+(?:Address|DOB|Gender|Male|Female|\d{4}\s\d{4}\s\d{4}))/i,
        /(?:Care of|C\/O)[:\s]*([A-Za-z\s]+?)(?=\s+(?:Address|DOB|\d{4}\s\d{4}\s\d{4}))/i
      ]);

      // Aadhaar number - handle both spaced and unspaced formats
      const aadhaarMatch = text.match(/\b(\d{4}\s\d{4}\s\d{4})\b/) || 
                          text.match(/\b(\d{12})\b/);
      if (aadhaarMatch) {
        info.documentNumber = aadhaarMatch[1];
      }

      // Date of Birth - multiple formats
      const dobMatch = text.match(/(?:DOB|Date of Birth|जन्म तिथि)[:\s]*(\d{1,2}[\/\-]\d{1,2}[\/\-]\d{4})/i) ||
                      text.match(/(\d{2}\/\d{2}\/\d{4})/) || // Standalone date format
                      text.match(/(\d{1,2}[\/\-]\d{1,2}[\/\-]\d{4})/);
      if (dobMatch) {
        info.dateOfBirth = dobMatch[1];
      }

      // Gender - both English and Hindi
      const genderMatch = text.match(/(?:Gender|लिंग)[:\s]*(Male|Female|पुरुष|महिला)/i) ||
