      } else if (status === 'failed') {
        throw new Error(`Document analysis failed: ${resultResponse.data.error?.message || 'Unknown error'}`);
      }

      // Log progress for debugging
      console.log(`Polling attempt ${attempts + 1}/${maxAttempts}, status: ${status}`);

    } catch (pollError) {
      // Handle network errors during polling
      if (attempts >= maxAttempts - 1) {
        throw new Error(`Polling failed after ${attempts + 1} attempts: ${pollError.message}`);
      }
      console.log(`Poll attempt ${attempts + 1} failed, retrying...`);
    }

    attempts++;
  }

  if (!resultResponse || resultResponse.data.status !== 'succeeded') {
    throw new Error(`Document analysis timed out after ${maxAttempts * pollInterval / 1000} seconds`);
  }

  // Step 3: Extract text from the results
  let extractedText = '';
  const analysisResult = resultResponse.data.analyzeResult;

  if (analysisResult && analysisResult.content) {
    extractedText = analysisResult.content;
  } else if (analysisResult && analysisResult.pages) {
    // Fallback: extract from pages if content is not available
    extractedText = analysisResult.pages
      .map(page => {
        if (page.lines) {
          return page.lines.map(line => line.content).join(' ');
        }
        return '';
      })
      .join(' ');
  }

  // 🌍 Function to check if passport is Indian
  function isIndianPassport(text) {
    if (!text) return false;
    const lowerText = text.toLowerCase();

    // Check for Indian passport indicators
    const indianIndicators = [
      lowerText.includes("republic of india"),
      lowerText.includes("भारत गणराज्य"),
      lowerText.includes("government of india"),
      lowerText.includes("ministry of external affairs"),
      lowerText.includes("विदेश मंत्रालय"),
      lowerText.includes("भारत सरकार"),
      /nationality[\/\s]*[:\s]*indian/i.test(text),
      /राष्ट्रीयता[\/\s]*[:\s]*भारतीय/i.test(text)
    ];

    // Return true if at least 2 indicators are present
    const indicatorCount = indianIndicators.filter(Boolean).length;
    return indicatorCount >= 2;
  }

  // 🔍 Advanced document type detection
  function detectDocumentType(text) {
    if (!text) return "unknown";
    const lowerText = text.toLowerCase();
    const normalizedText = text.replace(/\s+/g, ' ').trim();

    // Priority 1: Aadhaar Card Detection
    const aadhaarIndicators = [
      lowerText.includes("aadhaar"),
      lowerText.includes("unique identification"),
      lowerText.includes("uidai"),
      lowerText.includes("आधार"),
      lowerText.includes("मेरा आधार"),
      /\b\d{4}\s\d{4}\s\d{4}\b/.test(normalizedText) && lowerText.includes("government of india")
    ];
    if (aadhaarIndicators.filter(Boolean).length >= 2) {
      return "aadhaar";
    }

    // Priority 2: Driving License Detection
    const dlIndicators = [
      lowerText.includes("driving license") || lowerText.includes("driving licence"),
      lowerText.includes("licence to drive") || lowerText.includes("license to drive"),
      lowerText.includes("dl no") || lowerText.includes("dl:"),
      lowerText.includes("transport department"),
      lowerText.includes("motor vehicle"),
      lowerText.includes("auth to drive") || lowerText.includes("authorisation to drive"),
      lowerText.includes("vehicles throughout india"),
      lowerText.includes("validity(nt)") || lowerText.includes("validity(t)"),
      /dl[\s\-]*\d{2}[\s\-]*\d{8,}/i.test(text),
      lowerText.includes("cov") && lowerText.includes("mcwg"),
      lowerText.includes("transport vehicle") || lowerText.includes("non-transport"),
      lowerText.includes("date of issue") && (lowerText.includes("auth") || lowerText.includes("cov"))
    ];
    const dlCount = dlIndicators.filter(Boolean).length;

    if (dlCount >= 2) {
      return "driving_license";
    }

    // Priority 3: PAN Card Detection
    const panIndicators = [
      lowerText.includes("income tax"),
      lowerText.includes("permanent account number"),
      /[a-z]{5}[0-9]{4}[a-z]{1}/i.test(text) && !lowerText.includes("passport"),
      lowerText.includes("tax payer")
    ];
    if (panIndicators.filter(Boolean).length >= 2) {
      return "pan";
    }

    // Priority 4: Voter ID Detection
    const voterIndicators = [
      lowerText.includes("voter") || lowerText.includes("elector"),
      lowerText.includes("election commission"),
      lowerText.includes("epic"),
      lowerText.includes("मतदाता") || lowerText.includes("निर्वाचन"),
      lowerText.includes("electoral photo identity"),
      lowerText.includes("constituency"),
      /[a-z]{3}\d{7}/i.test(text) && !lowerText.includes("passport") && !lowerText.includes("license"),
      lowerText.includes("part no") && lowerText.includes("serial no")
    ];
    if (voterIndicators.filter(Boolean).length >= 3) {
      return "voter_id";
    }

    // Priority 5: Passport Detection
    const passportIndicators = [
      lowerText.includes("passport"),
      lowerText.includes("republic of india") && lowerText.includes("passport"),
      lowerText.includes("ministry of external affairs"),
      lowerText.includes("विदेश मंत्रालय"),
      lowerText.includes("date of expiry") && lowerText.includes("nationality"),
      lowerText.includes("given name") && lowerText.includes("surname") && !lowerText.includes("license"),
      lowerText.includes("place of issue") || lowerText.includes("place of birth"),
      /p\d{7}/i.test(text) && lowerText.includes("passport")
    ];
    const passportCount = passportIndicators.filter(Boolean).length;

    if (passportCount >= 3 && dlCount < 2) {
      return "passport";
    }

    if (dlCount === 1 && passportCount < 3) {
      return "driving_license";
    }

    return "unknown";
