    Status: 'SUCCESS',
    Confidence_Score: 90,
    Error_Message: null,
    fileName: dynamicFileName,
    azurePath: blobPath,
    documentType: docType,
    constituency: extractedInfo.constituency || 'Not Found'
  };

  // Set document value
  result.Document_Value = formatDocumentValue(result);

  // Validate if we extracted meaningful information
  const hasValidInfo = (result.Name !== 'Not Found') || 
                      (result.Document_Number !== 'Not Found') || 
                      (result.Date_of_Birth !== 'Not Found');

  if (!hasValidInfo) {
    result.Status = 'FAILED';
    result.Confidence_Score = 0;
