// N8N Code Node to calculate notification time (24 hours before 12 noon of check-in date)

const processedItems = [];

for (const item of $input.all()) {
  const data = item.json;

  let checkInDate;
  let notificationTime;

  try {
    // Handle different date formats
    if (typeof data["Check-In Date"] === 'string') {
      // String format like "2025-07-22"
      checkInDate = new Date(data["Check-In Date"]);
    } else if (typeof data["Check-In Date"] === 'number') {
      // Excel serial number format (days since 1900-01-01, with leap year bug)
      // Formula: (serial - 25569) * 86400000 to convert to JavaScript timestamp
      const excelSerialDate = data["Check-In Date"];
      checkInDate = new Date((excelSerialDate - 25569) * 86400000);
    } else {
      throw new Error('Invalid date format');
    }

    // Validate the date
    if (isNaN(checkInDate.getTime())) {
      throw new Error('Invalid date');
    }

    // Set time to 12:00 PM (noon) on check-in date
    const noonCheckIn = new Date(checkInDate);
    noonCheckIn.setHours(12, 0, 0, 0);

    // Calculate 24 hours before (which is 12:00 PM the day before)
    notificationTime = new Date(noonCheckIn.getTime() - (24 * 60 * 60 * 1000));

    // Add the calculated notification time to the data
    const processedItem = {
      ...data,
      "Notification_Time": notificationTime.toISOString(),
      "Notification_Time_Local": notificationTime.toLocaleString('en-IN', {
        timeZone: 'Asia/Kolkata',
        year: 'numeric',
        month: '2-digit',
        day: '2-digit'
      }),
     "Check-In Date Parsed": checkInDate.toLocaleString('en-IN', {
  timeZone: 'Asia/Kolkata',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit'
})
    };

    processedItems.push({ json: processedItem });

  } catch (error) {
    // Handle invalid dates gracefully
    const processedItem = {
      ...data,
      "Notification_Time": null,
      "Notification_Time_Local": null,
      "Check-In Date Parsed": "Invalid Date",
      "Error": `Failed to parse date: ${data["Check-In Date"]}`
    };

    processedItems.push({ json: processedItem });
  }
}

return processedItems;

