// Document Selection JSON Generator for n8n
// This script processes document data and creates a WhatsApp message JSON
// Modified to return in payment script structure format
// Updated to only process documents with URLs that match Microsoft SQL55 Document_URLs

function generateDocumentSelectionJSON(inputData) {
  // Get the Document_URLs from Microsoft SQL55 node
  const sqlData = $('Microsoft SQL55').first().json;
  const allowedUrls = sqlData.Document_URLs;

  // Convert allowedUrls to array if it's a string (comma-separated URLs)
  let urlArray = [];
  if (typeof allowedUrls === 'string') {
    urlArray = allowedUrls.split(',').map(url => url.trim());
  } else if (Array.isArray(allowedUrls)) {
    urlArray = allowedUrls;
  } else {
    urlArray = [allowedUrls]; // Single URL
  }

  // Filter input data to only include documents with URLs that are in the allowed URLs
  const filteredDocs = inputData.filter(doc => {
    // Check if the document has a URL property that matches any of the allowed URLs
    const docUrl = doc.Document_URL || doc.URL || doc.url || doc.Image_URL;
    return docUrl && urlArray.includes(docUrl);
  });

  // Filter successful documents only from the filtered set
  const successfulDocs = filteredDocs.filter(doc => doc.Success === true || doc.Success === "true");

  if (successfulDocs.length === 0) {
    return {
      json: {
        "message": {
          "messaging_product": "whatsapp",
          "recipient_type": "individual",
          "to": $('Webhook').first().json.body.userSession.userPhoneNumber,
          "type": "text",
          "text": {
            "body": "❌ No valid documents found for the specified URLs. Please upload clear, high-quality images of your documents and try again."
          }
        },
        "phone": $('Webhook').first().json.body.userSession.userPhoneNumber,
        "business_phone_number_id": "606239485906302",
        "access_token": "EAAVZBobCt7AcBO3Y2khw99wNz6HgSVt2ciXhYy29e33C6LHB1GBokvSbtX2YGKwxdiue22o9x5yo0QyDkUq0QZBUA57fNBeTAq6ZBw7HHcxVXfIrZBgErKEYB90pxkiqPXqrvqIAf0sCClJwQxnZCEFT9Umo7guGs8X5R0xRabOawKb2mTek7lRx2ZCyAyTjQgJ5ZA8LN8rabdz4yibKxHTp8NYrNDKSyAw0AP0nx3Aap5MdmNJjl2nQwZATBvDy",
        "tenant_id": "hjiqohe",
        "custom": true
      }
    };
  }

  // Helper function to extract key information from different document types
  function extractDocumentInfo(doc) {
    const docType = doc.Document_Type;
    const docName = doc.Doc_Name;
    const extractedText = doc.Extracted_Text;
    const docValue = doc.Document_Value;

    let info = {};

    switch (docType) {
      case "Passport":
        // Extract surname and issue date if available
        info.displayName = docName.includes("Surname:") ? 
          docName.split("Surname:")[1]?.split("(")[0]?.trim() : 
          docName;

        // Try to extract issue date from docName or extractedText
        const passportIssueMatch = docName.match(/Issued:\s*(\d{2}\/\d{2}\/\d{4})/);
        info.issueDate = passportIssueMatch ? passportIssueMatch[1] : "Date not found";
        info.emoji = "📘";
        break;

      case "Driving License":
        // Extract name from doc_name or extracted text
        info.displayName = docName.includes("DOB") ? 
          docName.split(" DOB")[0] : 
          docName;

        // Try to extract issue date from extracted text
        const dlIssueMatch = extractedText.match(/Issue Date[:\s]*(\d{2}\/\d{2}\/\d{4})/);
        info.issueDate = dlIssueMatch ? dlIssueMatch[1] : "Date not found";
        info.emoji = "🚗";
        break;

      case "Aadhaar Card":
        // Extract name and DOB
        const aadhaarMatch = docName.match(/(.+)\s+DOB\s+(\d{2}\/\d{2}\/\d{4})/);
        if (aadhaarMatch) {
          info.displayName = aadhaarMatch[1].trim();
          info.issueDate = `DOB: ${aadhaarMatch[2]}`;
        } else {
          info.displayName = docName;
          info.issueDate = "DOB not found";
        }
        info.emoji = "🆔";
        break;

      default:
        info.displayName = docName;
        info.issueDate = "Date not available";
        info.emoji = "📄";
    }

    return info;
  }

  // Use filtered successful documents
  const uniqueDocs = successfulDocs;

  // Create numbered list of documents
  let messageBody = "📋 *Documents Detected*\n\n";
  messageBody += "Please verify the information below and select the documents you'd like to use:\n\n";

  uniqueDocs.forEach((doc, index) => {
    const info = extractDocumentInfo(doc);
    const number = index + 1;

    messageBody += `*${number}. ${doc.Document_Type}*\n`;
    messageBody += `   👤 Name: ${info.displayName}\n`;
    messageBody += `   📅 ${info.issueDate}\n`;

    // Add quality indicator if available
    if (doc.Quality) {
      const qualityStatus = doc.Quality >= 100 ? "✅ Good Quality" : "⚠️ Fair Quality";
      messageBody += `   🔍 ${qualityStatus}\n`;
    }

    messageBody += "\n";
  });

  // Create the final JSON structure in payment script format
  const result = {
    json: {
      "message": {
        "messaging_product": "whatsapp",
        "recipient_type": "individual",
        "to": $('Webhook').first().json.body.userSession.userPhoneNumber,
        "type": "text",
        "text": {
          "body": messageBody
        }
      },
      "phone": $('Webhook').first().json.body.userSession.userPhoneNumber,
      "business_phone_number_id": "606239485906302",
      "access_token": "EAAVZBobCt7AcBO3Y2khw99wNz6HgSVt2ciXhYy29e33C6LHB1GBokvSbtX2YGKwxdiue22o9x5yo0QyDkUq0QZBUA57fNBeTAq6ZBw7HHcxVXfIrZBgErKEYB90pxkiqPXqrvqIAf0sCClJwQxnZCEFT9Umo7guGs8X5R0xRabOawKb2mTek7lRx2ZCyAyTjQgJ5ZA8LN8rabdz4yibKxHTp8NYrNDKSyAw0AP0nx3Aap5MdmNJjl2nQwZATBvDy",
      "tenant_id": "hjiqohe",
      "custom": true,
      "documentData": {
        "totalDocuments": uniqueDocs.length,
        "successfulDocuments": successfulDocs.length,
        "filteredByUrls": true,
        "allowedUrls": urlArray,
        "detectedDocuments": uniqueDocs.map((doc, index) => ({
          "index": index + 1,
          "type": doc.Document_Type,
          "name": doc.Doc_Name,
          "quality": doc.Quality || null,
          "success": doc.Success,
          "url": doc.Document_URL || doc.URL || doc.url || doc.Image_URL
        }))
      }
    }
  };

  return result;
}

// For n8n usage - Get input data from previous node
const inputData = $input.all().map(item => item.json);

// Generate the result
