      message: "Could not find binary data named 'data' from previous node",
      availableBinaryKeys: inputData.binary ? Object.keys(inputData.binary) : 'No binary data'
    }
  }];
}

// Extract the actual buffer from the binary data object
let bufferData;
if (binaryDataObject.data) {
  // If it has a .data property, use that
  bufferData = Buffer.from(binaryDataObject.data, 'base64');
} else if (Buffer.isBuffer(binaryDataObject)) {
  // If it's already a buffer
  bufferData = binaryDataObject;
} else if (typeof binaryDataObject === 'string') {
  // If it's a base64 string
  bufferData = Buffer.from(binaryDataObject, 'base64');
} else {
  return [{
    json: {
      error: "❌ Unsupported binary data format",
      message: "Could not extract buffer from binary data object",
      dataType: typeof binaryDataObject,
      dataKeys: Object.keys(binaryDataObject),
      isBuffer: Buffer.isBuffer(binaryDataObject)
    }
  }];
}

// Determine file type and extension based on content type and file signature
function getFileInfo(contentType, buffer) {
  let fileExtension = 'bin';
  let fileType = 'unknown';

  // Check magic bytes/file signatures
  const signature = buffer.slice(0, 8);
  const signatureHex = signature.toString('hex').toUpperCase();
  const signatureString = signature.toString();

  if (signatureString.startsWith('%PDF')) {
    fileType = 'pdf';
    fileExtension = 'pdf';
  } else if (signatureHex.startsWith('FFD8FF')) {
    fileType = 'image';
    fileExtension = 'jpg';
  } else if (signatureHex.startsWith('89504E47')) {
    fileType = 'image';
    fileExtension = 'png';
  } else if (signatureHex.startsWith('47494638')) {
    fileType = 'image';
    fileExtension = 'gif';
  } else if (signatureHex.startsWith('424D')) {
    fileType = 'image';
    fileExtension = 'bmp';
  } else if (signatureHex.startsWith('52494646') && signatureHex.includes('57454250')) {
    fileType = 'image';
    fileExtension = 'webp';
  } else {
    // Fallback to content type
    if (contentType.includes('pdf')) {
      fileType = 'pdf';
      fileExtension = 'pdf';
    } else if (contentType.includes('image')) {
      fileType = 'image';
      const typeMap = {
        'image/jpeg': 'jpg',
        'image/jpg': 'jpg',
        'image/png': 'png',
        'image/gif': 'gif',
        'image/bmp': 'bmp',
        'image/webp': 'webp',
        'image/svg+xml': 'svg'
      };
      fileExtension = typeMap[contentType] || 'jpg';
    }
  }

  return { fileType, fileExtension };
}

