const axios = require('axios');

// 🔐 Azure Document Intelligence Config
const docIntelligenceKey = "f1ecbfcb87c84851bc85735f3694696c";
const docIntelligenceEndpoint = "https://zestayocr.cognitiveservices.azure.com/";

// 📦 Azure Blob File Config
const account = "pdffornurenai";
const container = "pdf";

try {
  // 📲 Get phone number and build file path
  const phoneNumber = $('Webhook').first().json.body.userSession.userPhoneNumber;
  const uniqueId = Date.now();
  const fileName = `document_${uniqueId}.jpg`;
  const blobPath = `${phoneNumber}/${fileName}`;

  // 🔗 Full Azure Blob URL
  const imageUrl = $input.first().json.blobUrl;

  console.log(`Processing image with Document Intelligence: ${imageUrl}`);

  // Step 1: Submit document for analysis using the general document model
  const analyzeResponse = await axios.post(
    `${docIntelligenceEndpoint}/formrecognizer/documentModels/prebuilt-document:analyze?api-version=2023-07-31`,
    { urlSource: imageUrl },
    {
      headers: {
        'Ocp-Apim-Subscription-Key': docIntelligenceKey,
        'Content-Type': 'application/json'
      },
      timeout: 30000
    }
  );

  // Get the operation location from response headers
  const operationLocation = analyzeResponse.headers['operation-location'];
  if (!operationLocation) {
    throw new Error('No operation location returned from Document Intelligence');
  }

  // ⚡ FIXED: Step 2 - Improved polling mechanism
  let resultResponse;
  let attempts = 0;
  const maxAttempts = 20; // Reduced from 30
  const pollInterval = 1500; // 1.5 seconds instead of 2

  // Create a promise-based delay function
  const delay = (ms) => new Promise(resolve => setTimeout(resolve, ms));

  while (attempts < maxAttempts) {
    // Wait before polling (except first attempt)
    if (attempts > 0) {
      await delay(pollInterval);
    }

    try {
      resultResponse = await axios.get(operationLocation, {
        headers: {
          'Ocp-Apim-Subscription-Key': docIntelligenceKey
        },
        timeout: 10000 // Add timeout to prevent hanging
      });

      const status = resultResponse.data.status;

      if (status === 'succeeded') {
        console.log(`Document analysis succeeded after ${attempts + 1} attempts`);
        break;
      } else if (status === 'failed') {
        throw new Error(`Document analysis failed: ${resultResponse.data.error?.message || 'Unknown error'}`);
      }

      // Log progress for debugging
      console.log(`Polling attempt ${attempts + 1}/${maxAttempts}, status: ${status}`);

    } catch (pollError) {
      // Handle network errors during polling
      if (attempts >= maxAttempts - 1) {
        throw new Error(`Polling failed after ${attempts + 1} attempts: ${pollError.message}`);
      }
      console.log(`Poll attempt ${attempts + 1} failed, retrying...`);
    }

    attempts++;
  }

  if (!resultResponse || resultResponse.data.status !== 'succeeded') {
    throw new Error(`Document analysis timed out after ${maxAttempts * pollInterval / 1000} seconds`);
  }

  // Step 3: Extract text from the results
  let extractedText = '';
  const analysisResult = resultResponse.data.analyzeResult;

  if (analysisResult && analysisResult.content) {
    extractedText = analysisResult.content;
  } else if (analysisResult && analysisResult.pages) {
    // Fallback: extract from pages if content is not available
    extractedText = analysisResult.pages
      .map(page => {
        if (page.lines) {
          return page.lines.map(line => line.content).join(' ');
        }
        return '';
      })
      .join(' ');
  }

  // 🌍 Function to check if passport is Indian
  function isIndianPassport(text) {
    if (!text) return false;
    const lowerText = text.toLowerCase();

    // Check for Indian passport indicators
    const indianIndicators = [
      lowerText.includes("republic of india"),
      lowerText.includes("भारत गणराज्य"),
      lowerText.includes("government of india"),
      lowerText.includes("ministry of external affairs"),
      lowerText.includes("विदेश मंत्रालय"),
      lowerText.includes("भारत सरकार"),
      /nationality[\/\s]*[:\s]*indian/i.test(text),
      /राष्ट्रीयता[\/\s]*[:\s]*भारतीय/i.test(text)
    ];

    // Return true if at least 2 indicators are present
    const indicatorCount = indianIndicators.filter(Boolean).length;
    return indicatorCount >= 2;
  }

  // 🔍 Advanced document type detection
  function detectDocumentType(text) {
    if (!text) return "unknown";
    const lowerText = text.toLowerCase();
    const normalizedText = text.replace(/\s+/g, ' ').trim();

    // Priority 1: Aadhaar Card Detection
    const aadhaarIndicators = [
      lowerText.includes("aadhaar"),
      lowerText.includes("unique identification"),
      lowerText.includes("uidai"),
      lowerText.includes("आधार"),
      lowerText.includes("मेरा आधार"),
      /\b\d{4}\s\d{4}\s\d{4}\b/.test(normalizedText) && lowerText.includes("government of india")
    ];
    if (aadhaarIndicators.filter(Boolean).length >= 2) {
      return "aadhaar";
    }

    // Priority 2: Driving License Detection
    const dlIndicators = [
      lowerText.includes("driving license") || lowerText.includes("driving licence"),
      lowerText.includes("licence to drive") || lowerText.includes("license to drive"),
      lowerText.includes("dl no") || lowerText.includes("dl:"),
      lowerText.includes("transport department"),
      lowerText.includes("motor vehicle"),
      lowerText.includes("auth to drive") || lowerText.includes("authorisation to drive"),
      lowerText.includes("vehicles throughout india"),
      lowerText.includes("validity(nt)") || lowerText.includes("validity(t)"),
      /dl[\s\-]*\d{2}[\s\-]*\d{8,}/i.test(text),
      lowerText.includes("cov") && lowerText.includes("mcwg"),
      lowerText.includes("transport vehicle") || lowerText.includes("non-transport"),
      lowerText.includes("date of issue") && (lowerText.includes("auth") || lowerText.includes("cov"))
    ];
    const dlCount = dlIndicators.filter(Boolean).length;

    if (dlCount >= 2) {
      return "driving_license";
    }

    // Priority 3: PAN Card Detection
    const panIndicators = [
      lowerText.includes("income tax"),
      lowerText.includes("permanent account number"),
      /[a-z]{5}[0-9]{4}[a-z]{1}/i.test(text) && !lowerText.includes("passport"),
      lowerText.includes("tax payer")
    ];
    if (panIndicators.filter(Boolean).length >= 2) {
      return "pan";
    }

    // Priority 4: Voter ID Detection
    const voterIndicators = [
      lowerText.includes("voter") || lowerText.includes("elector"),
      lowerText.includes("election commission"),
      lowerText.includes("epic"),
      lowerText.includes("मतदाता") || lowerText.includes("निर्वाचन"),
      lowerText.includes("electoral photo identity"),
      lowerText.includes("constituency"),
      /[a-z]{3}\d{7}/i.test(text) && !lowerText.includes("passport") && !lowerText.includes("license"),
      lowerText.includes("part no") && lowerText.includes("serial no")
    ];
    if (voterIndicators.filter(Boolean).length >= 3) {
      return "voter_id";
    }

    // Priority 5: Passport Detection
    const passportIndicators = [
      lowerText.includes("passport"),
      lowerText.includes("republic of india") && lowerText.includes("passport"),
      lowerText.includes("ministry of external affairs"),
      lowerText.includes("विदेश मंत्रालय"),
      lowerText.includes("date of expiry") && lowerText.includes("nationality"),
      lowerText.includes("given name") && lowerText.includes("surname") && !lowerText.includes("license"),
      lowerText.includes("place of issue") || lowerText.includes("place of birth"),
      /p\d{7}/i.test(text) && lowerText.includes("passport")
    ];
    const passportCount = passportIndicators.filter(Boolean).length;

    if (passportCount >= 3 && dlCount < 2) {
      return "passport";
    }

    if (dlCount === 1 && passportCount < 3) {
      return "driving_license";
    }

    return "unknown";
  }

  const docType = detectDocumentType(extractedText);

  // 🚨 Check if it's a non-Indian passport
  if (docType === "passport" && !isIndianPassport(extractedText)) {
    const nonIndianPassportError = {
      Guest_Phone: phoneNumber || '',
      Document_URL: imageUrl || '',
      Document_Type: 'NON_INDIAN_PASSPORT',
      Name: 'Foreign Passport Detected',
      Age: null,
      Date_of_Birth: 'Not Applicable',
      Address: 'Not Applicable',
      Document_Number: 'Not Extracted',
      Father_Name: 'Not Applicable',
      Gender: 'Not Found',
      Blood_Group: 'Not Applicable',
      Issue_Date: 'Not Found',
      Valid_Till: 'Not Found',
      Place_of_Birth: 'Not Found',
      Nationality: 'NON-INDIAN',
      Document_Value: 'Only Indian passports are accepted. Please upload a valid Indian passport or other accepted Indian identity document (Aadhaar, Driving License, Voter ID).',
      Extracted_Text: extractedText || "No text detected",
      Upload_Date: new Date().toISOString().split('T')[0],
      Unique_ID: `doc_${Date.now()}_${Math.floor(Math.random() * 1000)}`,
      Status: 'REJECTED',
      Confidence_Score: 0,
      Error_Message: 'Non-Indian passport detected. Only Indian passports are accepted. Please upload an Indian passport, Aadhaar Card, Driving License, or Voter ID.'
    };

    return [nonIndianPassportError];
  }

  // Check if document type is supported
  const supportedDocTypes = ["aadhaar", "driving_license", "passport", "voter_id"];
  if (!supportedDocTypes.includes(docType)) {
    const errorResult = {
      Guest_Phone: phoneNumber || '',
      Document_URL: imageUrl || '',
      Document_Type: 'UNSUPPORTED_DOCUMENT',
      Name: 'Unsupported Document Type',
      Age: null,
      Date_of_Birth: 'Not Found',
      Address: 'Not Found',
      Document_Number: 'Not Found',
      Father_Name: 'Not Found',
      Gender: 'Not Found',
      Blood_Group: 'Not Found',
      Issue_Date: 'Not Found',
      Valid_Till: 'Not Found',
      Place_of_Birth: 'Not Found',
      Nationality: 'Not Found',
      Document_Value: `Unsupported document type '${docType}'. Only Aadhaar Card, Driving License, Passport, and Voter ID are accepted.`,
      Extracted_Text: extractedText || "No text detected",
      Upload_Date: new Date().toISOString().split('T')[0],
      Unique_ID: `doc_${Date.now()}_${Math.floor(Math.random() * 1000)}`,
      Status: 'FAILED',
      Confidence_Score: 0,
      Error_Message: `Document type '${docType}' is not supported. Only Aadhaar Card, Driving License, Passport, and Voter ID are accepted.`
    };

    return [errorResult];
  }

  // 📝 Extract specific information based on document type
  function extractDocumentInfo(text, docType) {
    const info = {
      holderName: null,
      fatherName: null,
      documentNumber: null,
      dateOfBirth: null,
      address: null,
      gender: null,
      issueDate: null,
      validityDate: null,
      placeOfBirth: null,
      constituency: null
    };

    // Helper function to clean extracted text
    function cleanText(str) {
      return str ? str.replace(/\n/g, ' ').replace(/\s+/g, ' ').trim() : null;
    }

    // Helper function to extract name with multiple fallback patterns
    function extractNameMultiplePatterns(patterns) {
      for (const pattern of patterns) {
        const match = text.match(pattern);
        if (match && match[1] && match[1].trim().length > 1) {
          return cleanText(match[1]);
        }
      }
      return null;
    }

    if (docType === "aadhaar") {
      // Enhanced name extraction for Aadhaar
      info.holderName = extractNameMultiplePatterns([
        /([A-Z][a-z]+(?:\s+[A-Z][a-z]+)*)\s+जन्म तिथि/i,
        /([A-Z][a-z]+(?:\s+[A-Z][a-z]+)*)\s+DOB/i,
        /[^\w\s]+\s*([A-Z][a-z]+(?:\s+[A-Z][a-z]+)*)\s+([A-Z][a-z]+(?:\s+[A-Z][a-z]+)*)/i,
        /(?:Name|नाम)[:\s]*([A-Za-z\s]+?)(?=\s+(?:जन्म|DOB|Date of Birth|Gender|Male|Female))/i,
        /([A-Z][a-z]+(?:\s+[A-Z][a-z]+)*)\s+(?:जन्म तिथि|DOB)[:\s]/i,
        /([A-Z][a-z]+(?:\s+[A-Z][a-z]+)*)\s+(?:\d{2}\/\d{2}\/\d{4}|Male|Female|पुरुष|महिला)/i
      ]);

      info.fatherName = extractNameMultiplePatterns([
        /(?:Father|पिता|S\/O|Son of)[:\s]*([A-Za-z\s]+?)(?=\s+(?:Address|DOB|Gender|Male|Female|\d{4}\s\d{4}\s\d{4}))/i,
        /(?:Care of|C\/O)[:\s]*([A-Za-z\s]+?)(?=\s+(?:Address|DOB|\d{4}\s\d{4}\s\d{4}))/i
      ]);

      const aadhaarMatch = text.match(/\b(\d{4}\s\d{4}\s\d{4})\b/) || text.match(/\b(\d{12})\b/);
      if (aadhaarMatch) {
        info.documentNumber = aadhaarMatch[1];
      }

      const dobMatch = text.match(/(?:DOB|Date of Birth|जन्म तिथि)[:\s]*(\d{1,2}[\/\-]\d{1,2}[\/\-]\d{4})/i) ||
                      text.match(/(\d{2}\/\d{2}\/\d{4})/) ||
                      text.match(/(\d{1,2}[\/\-]\d{1,2}[\/\-]\d{4})/);
      if (dobMatch) {
        info.dateOfBirth = dobMatch[1];
      }

      const genderMatch = text.match(/(?:Gender|लिंग)[:\s]*(Male|Female|पुरुष|महिला)/i) ||
                         text.match(/(Male|Female|पुरुष|महिला)/i);
      if (genderMatch) {
        info.gender = genderMatch[1];
      }

      const addressMatch = text.match(/(?:Address|पता)[:\s]*([^।]*?)(?=\d{4}\s\d{4}\s\d{4}|$)/i);
      if (addressMatch) {
        info.address = cleanText(addressMatch[1]);
      }
    }

    else if (docType === "driving_license") {
      info.holderName = extractNameMultiplePatterns([
        /(?:Name)[:\s]*([A-Z][A-Z\s]+?)(?=\s+S\/W\/D|Father|Issue Date|DOB)/i,
