        /Name[:\s]*([A-Za-z\s]+?)(?=\n|S\/|Father)/i
      ]);

      info.fatherName = extractNameMultiplePatterns([
        /(?:S\/W\/D)[:\s]*([A-Z][A-Z\s]+?)(?=\s+(?:Issue Date|DOB|Address|BG))/i,
        /(?:Father|Son of|पिता)[:\s]*([A-Za-z\s]+?)(?=\s+(?:Issue Date|DOB|Address|BG))/i
      ]);

