  // Calculate age
  const age = calculateAge(cleanDOB);

  // Create filename with holder name if available
  let dynamicFileName = fileName;
  if (cleanName && cleanName !== 'Not Found') {
    const cleanNameForFile = cleanName.replace(/[^a-zA-Z0-9]/g, '_').toLowerCase();
    dynamicFileName = `${docType}_${cleanNameForFile}_${uniqueId}.jpg`;
  }

  // Create result object in the expected format
  const result = {
    Guest_Phone: phoneNumber,
    Document_URL: imageUrl,
    Document_Type: standardizedDocType,
    Name: cleanName,
