const axios = require('axios');

// Get the file data from the previous HTTP node and HTTP Request65
const inputData = $input.first();
const httpRequest65Data = $('HTTP Request65').first();

// Function to extract buffer from binary data object
function extractBuffer(binaryDataObject, sourceName) {
  if (!binaryDataObject) {
    throw new Error(`No binary data found in ${sourceName}`);
  }

  let bufferData;
  if (binaryDataObject.data) {
    // If it has a .data property, use that
    bufferData = Buffer.from(binaryDataObject.data, 'base64');
  } else if (Buffer.isBuffer(binaryDataObject)) {
    // If it's already a buffer
    bufferData = binaryDataObject;
  } else if (typeof binaryDataObject === 'string') {
    // If it's a base64 string
    bufferData = Buffer.from(binaryDataObject, 'base64');
  } else {
    throw new Error(`Unsupported binary data format in ${sourceName}`);
  }

  return bufferData;
}

// Function to determine file type and extension
function getFileInfo(contentType, buffer) {
  let fileExtension = 'bin';
  let fileType = 'unknown';

  // Check magic bytes/file signatures
  const signature = buffer.slice(0, 8);
  const signatureHex = signature.toString('hex').toUpperCase();
  const signatureString = signature.toString();

  if (signatureString.startsWith('%PDF')) {
    fileType = 'pdf';
    fileExtension = 'pdf';
  } else if (signatureHex.startsWith('FFD8FF')) {
    fileType = 'image';
    fileExtension = 'jpg';
  } else if (signatureHex.startsWith('89504E47')) {
    fileType = 'image';
    fileExtension = 'png';
  } else if (signatureHex.startsWith('47494638')) {
    fileType = 'image';
    fileExtension = 'gif';
  } else if (signatureHex.startsWith('424D')) {
    fileType = 'image';
    fileExtension = 'bmp';
  } else if (signatureHex.startsWith('52494646') && signatureHex.includes('574EB50')) {
    fileType = 'image';
    fileExtension = 'webp';
  } else {
    // Fallback to content type
    if (contentType && contentType.includes('pdf')) {
      fileType = 'pdf';
      fileExtension = 'pdf';
    } else if (contentType && contentType.includes('image')) {
      fileType = 'image';
      const typeMap = {
        'image/jpeg': 'jpg',
        'image/jpg': 'jpg',
        'image/png': 'png',
        'image/gif': 'gif',
        'image/bmp': 'bmp',
        'image/webp': 'webp',
        'image/svg+xml': 'svg'
      };
      fileExtension = typeMap[contentType] || 'jpg';
    }
  }

  return { fileType, fileExtension };
}

// Function to upload a file to Azure Blob Storage
async function uploadFile(bufferData, fileName, contentType, phoneNumber, account, container, sas) {
  const blobPath = `${phoneNumber}/${fileName}`;
  const uploadUrl = `https://${account}.blob.core.windows.net/${container}/${blobPath}?${sas}`;

  const response = await axios.put(uploadUrl, bufferData, {
    headers: {
      'x-ms-blob-type': 'BlockBlob',
      'Content-Type': contentType,
      'Content-Length': bufferData.length
    },
    maxBodyLength: Infinity,
    maxContentLength: Infinity,
    timeout: 60000
  });

  return {
    blobPath,
    blobUrl: `https://${account}.blob.core.windows.net/${container}/${blobPath}`,
    uploadStatus: response.status
  };
}

// Function to create a standardized result object
function createResult(fileNumber, success, data, error = null) {
  if (success) {
    return {
      fileNumber: fileNumber,
      success: true,
      message: `✅ Successfully uploaded ${data.detectedFileType} (File ${fileNumber}) to Azure Blob Storage`,
      filePath: data.filePath,
      blobUrl: data.blobUrl,
      fileSize: data.fileSize,
      originalSize: data.originalSize,
      contentType: data.contentType,
      detectedFileType: data.detectedFileType,
      fileExtension: data.fileExtension,
      uploadStatus: data.uploadStatus,
      isValid: data.isValid,
      timestamp: new Date().toISOString()
    };
  } else {
    return {
      fileNumber: fileNumber,
      success: false,
      error: `❌ Failed to process File ${fileNumber}`,
      message: error.message,
      details: error.toString(),
      timestamp: new Date().toISOString()
    };
  }
}

