// Function to analyze document using Azure Document Intelligence
async function analyzeDocument(blobUrl, modelId) {
  try {
    const url = `${endpoint}formrecognizer/documentModels/${modelId}:analyze?api-version=${apiVersion}`;

    const response = await axios.post(url, {
      urlSource: blobUrl
    }, {
      headers: {
        'Ocp-Apim-Subscription-Key': apiKey,
        'Content-Type': 'application/json'
      }
    });

    // Get the operation location from headers
    const operationLocation = response.headers['operation-location'];

    if (!operationLocation) {
      throw new Error('No operation location returned');
    }

    // Poll for results
    let result;
    let attempts = 0;
    const maxAttempts = 30;

    while (attempts < maxAttempts) {
      await new Promise(resolve => setTimeout(resolve, 2000));

      const statusResponse = await axios.get(operationLocation, {
        headers: {
          'Ocp-Apim-Subscription-Key': apiKey
        }
      });

      if (statusResponse.data.status === 'succeeded') {
        result = statusResponse.data;
        break;
      } else if (statusResponse.data.status === 'failed') {
        throw new Error(`Analysis failed: ${JSON.stringify(statusResponse.data.error)}`);
      }

      attempts++;
    }

    if (!result) {
      throw new Error('Analysis timed out');
    }

    return result;
  } catch (error) {
    console.error('Azure Document Intelligence error:', error.message);
    throw error;
  }
}

// Function to extract structured data using Azure Document Intelligence built-in models
function extractStructuredDataFromAzureResult(azureResult, documentType) {
  const data = {};

  // Extract from Azure's structured results
  if (azureResult.analyzeResult) {
    const analyzeResult = azureResult.analyzeResult;

    // Extract from documents array (contains structured fields)
    if (analyzeResult.documents && analyzeResult.documents.length > 0) {
      const document = analyzeResult.documents[0];

      // Map Azure's extracted fields to our required fields
      if (document.fields) {
        const fields = document.fields;

        // Common identity fields
        if (fields.FirstName) data.givenName = fields.FirstName.content || fields.FirstName.valueString;
        if (fields.LastName) data.surname = fields.LastName.content || fields.LastName.valueString;
        if (fields.Sex || fields.Gender) data.sex = (fields.Sex?.content || fields.Gender?.content || fields.Sex?.valueString || fields.Gender?.valueString);
        if (fields.DateOfBirth) data.dob = fields.DateOfBirth.content || fields.DateOfBirth.valueString;
        if (fields.Nationality) data.nationality = fields.Nationality.content || fields.Nationality.valueString;
        if (fields.CountryRegion) data.nationality = fields.CountryRegion.content || fields.CountryRegion.valueString;

        // Passport specific fields
        if (fields.DocumentNumber || fields.PassportNumber) {
          data.passportNo = fields.DocumentNumber?.content || fields.PassportNumber?.content || 
                           fields.DocumentNumber?.valueString || fields.PassportNumber?.valueString;
        }
        if (fields.PlaceOfIssue) data.passportIssuePlace = fields.PlaceOfIssue.content || fields.PlaceOfIssue.valueString;
        if (fields.DateOfIssue) data.passportIssueDate = fields.DateOfIssue.content || fields.DateOfIssue.valueString;
        if (fields.DateOfExpiration || fields.ExpirationDate) {
          data.passportValidTill = fields.DateOfExpiration?.content || fields.ExpirationDate?.content || 
                                  fields.DateOfExpiration?.valueString || fields.ExpirationDate?.valueString;
        }

        // Address fields
        if (fields.Address) data.permAddress = fields.Address.content || fields.Address.valueString;
        if (fields.City) data.permCity = fields.City.content || fields.City.valueString;
        if (fields.Country) data.permCountry = fields.Country.content || fields.Country.valueString;
        if (fields.State) data.refState = fields.State.content || fields.State.valueString;

        // Visa specific fields (if document type is visa)
        if (documentType === 'visa') {
          if (fields.VisaNumber || fields.ApplicationId) {
            data.visaNo = fields.VisaNumber?.content || fields.ApplicationId?.content || 
                         fields.VisaNumber?.valueString || fields.ApplicationId?.valueString;
          }
          if (fields.VisaType) data.visaType = fields.VisaType.content || fields.VisaType.valueString;
          if (fields.ValidFrom || fields.IssueDate) {
            data.visaIssueDate = fields.ValidFrom?.content || fields.IssueDate?.content || 
                               fields.ValidFrom?.valueString || fields.IssueDate?.valueString;
          }
          if (fields.ValidUntil || fields.ExpiryDate) {
            data.visaValidTill = fields.ValidUntil?.content || fields.ExpiryDate?.content || 
                               fields.ValidUntil?.valueString || fields.ExpiryDate?.valueString;
          }
          if (fields.PlaceOfIssue) data.visaIssuePlace = fields.PlaceOfIssue.content || fields.PlaceOfIssue.valueString;
        }
      }
    }

    // Enhanced extraction from key-value pairs for visa documents
    if (analyzeResult.keyValuePairs && documentType === 'visa') {
      for (const kvp of analyzeResult.keyValuePairs) {
        if (kvp.key && kvp.value) {
          const key = kvp.key.content?.toLowerCase();
          const value = kvp.value.content;

          // Enhanced mapping for visa-specific fields
          if (key?.includes('eta') && key?.includes('number')) data.visaNo = value;
          if (key?.includes('application') && key?.includes('id')) data.visaNo = value;
          if (key?.includes('visa') && key?.includes('type')) data.visaType = value;
          if (key?.includes('valid') && key?.includes('from')) data.visaIssueDate = value;
          if (key?.includes('valid') && key?.includes('until')) data.visaValidTill = value;
          if (key?.includes('issue') && key?.includes('date')) data.visaIssueDate = value;
          if (key?.includes('place') && key?.includes('issue')) data.visaIssuePlace = value;
          if (key?.includes('nationality')) data.nationality = value;
          if (key?.includes('passport') && key?.includes('no')) data.passportNo = value;
          if (key?.includes('name') && !data.givenName) {
            // Try to parse name if it contains a comma
            if (value.includes(',')) {
              const parts = value.split(',');
              data.surname = parts[0].trim();
              data.givenName = parts[1].trim().replace(/"/g, ''); // Remove quotes if present
            }
          }
        }
      }
    }

    // Extract from tables for additional visa information
    if (analyzeResult.tables && documentType === 'visa') {
      for (const table of analyzeResult.tables) {
        for (const cell of table.cells) {
          if (cell.content) {
            const content = cell.content.toLowerCase();

            // Look for visa information in table cells
            if (content.includes('eta') && content.includes('number') && cell.rowIndex === 1 && cell.columnIndex === 2) {
              // This is likely the visa number in the table
              data.visaNo = table.cells.find(c => c.rowIndex === cell.rowIndex && c.columnIndex === 2)?.content;
            }
            if (content.includes('visa') && content.includes('type') && cell.rowIndex === 2 && cell.columnIndex === 2) {
              data.visaType = table.cells.find(c => c.rowIndex === cell.rowIndex && c.columnIndex === 2)?.content;
            }
          }
        }
      }
    }
  }

  return data;
}

// Main document processing function
async function processDocument(blobUrl, documentType) {
  try {
    console.log(`Processing ${documentType} document using Azure Document Intelligence`);

    // Try different models based on document type
    let modelId = 'prebuilt-document'; // Default fallback

    if (documentType === 'passport') {
      // Try prebuilt-idDocument first for passports
      modelId = 'prebuilt-idDocument';
    } else if (documentType === 'visa') {
      // For visas, try prebuilt-document
      modelId = 'prebuilt-document';
    }

    const result = await analyzeDocument(blobUrl, modelId);

    if (!result.analyzeResult) {
      throw new Error('No analysis result from Azure Document Intelligence');
    }

    console.log(`Azure analysis completed for ${documentType}`);

    // Extract structured data using Azure's results
    const structuredData = extractStructuredDataFromAzureResult(result, documentType);

    return {
      success: true,
      documentType: documentType,
      data: structuredData,
      azureResult: result.analyzeResult // Include full Azure result for debugging
    };

  } catch (error) {
    console.error(`Failed to process ${documentType} document:`, error.message);

    // If prebuilt-idDocument fails for passport, try prebuilt-document
    if (documentType === 'passport' && error.message.includes('model')) {
      try {
        console.log('Retrying passport with prebuilt-document model');
        const result = await analyzeDocument(blobUrl, 'prebuilt-document');
        const structuredData = extractStructuredDataFromAzureResult(result, documentType);

        return {
          success: true,
          documentType: documentType,
          data: structuredData,
          azureResult: result.analyzeResult,
          note: 'Used fallback model'
        };
      } catch (retryError) {
        return {
          success: false,
          error: retryError.message,
          documentType: documentType,
          data: {}
        };
      }
    }

    return {
      success: false,
      error: error.message,
      documentType: documentType,
      data: {}
    };
  }
}

