// Helper function to format phone numbers to normal format
function formatPhoneNumber(phoneNumber) {
  if (!phoneNumber) return null;

  // Remove all non-digit characters except the leading +
  let cleaned = phoneNumber.toString().replace(/[^\d+]/g, '');

  // If it starts with +, remove country codes
  if (cleaned.startsWith('+')) {
    // Remove common country codes and format
    cleaned = cleaned.substring(1); // Remove the +

    // Remove common country codes
    if (cleaned.startsWith('44')) { // UK
      cleaned = cleaned.substring(2);
    } else if (cleaned.startsWith('91')) { // India
      cleaned = cleaned.substring(2);
    } else if (cleaned.startsWith('1')) { // US/Canada
      cleaned = cleaned.substring(1);
    }
    // Add more country codes as needed
  }

  // Return just the digits
  return cleaned;
}

// Helper function to extract address components
function parseAddress(address) {
  if (!address) return { city: null, country: null };

  const parts = address.split(',').map(part => part.trim());
  // Assume last part is country, second to last is city
  const country = parts.length > 1 ? parts[parts.length - 1] : null;
  const city = parts.length > 2 ? parts[parts.length - 2] : (parts.length === 2 ? parts[0] : null);

  return { city, country };
}

// Helper function to parse Indian address
function parseIndianAddress(address) {
  if (!address) return { place: null, district: null, state: null, pincode: null };

  // Try to extract pincode (6 digits)
  const pincodeMatch = address.match(/\b(\d{6})\b/);
  const pincode = pincodeMatch ? pincodeMatch[1] : null;

  // Remove pincode from address for further parsing
  let cleanAddress = address.replace(/\b\d{6}\b/, '').trim();

  // Split by comma and clean up
  const parts = cleanAddress.split(',').map(part => part.trim()).filter(part => part.length > 0);

  // Assume last part is state, second last is district, first is place
  const state = parts.length > 0 ? parts[parts.length - 1] : null;
  const district = parts.length > 1 ? parts[parts.length - 2] : null;
  const place = parts.length > 2 ? parts[0] : null;

  return { place, district, state, pincode };
}

