      // Universal passport data extraction (works for multiple countries)
      let surnameMatch, givenNameMatch, sexMatch, dobMatch, nationalityMatch, passportNoMatch;
      let issueDateMatch, expiryDateMatch, issuingCountryMatch, issuePlaceMatch;

      // Try different patterns for different passport formats

      // For Japanese passports
      surnameMatch = text.match(/姓\s*\/\s*Surname[:\s]*([A-Z\s]+)/i) || 
                    text.match(/Surname[:\s]*([A-Z\s]+)/i);
