// Validate JPEG format
function validateJPEG(buffer) {
  if (buffer.length < 4) return false;

  const signature = buffer.slice(0, 4);
  const signatureHex = signature.toString('hex').toUpperCase();

  // Check for JPEG SOI marker (FFD8)
  return signatureHex.startsWith('FFD8');
}

// JPEG compression by modifying quantization tables and reducing scan data
function compressJPEG(buffer, targetSizeKB = 45) {
  const targetBytes = targetSizeKB * 1024;

  if (buffer.length <= targetBytes) {
    return buffer;
  }

  console.log(`Compressing JPEG from ${(buffer.length/1024).toFixed(2)}KB to target ${targetSizeKB}KB`);

  // Find key JPEG segments
  let segments = [];
  let pos = 0;

  while (pos < buffer.length - 1) {
    if (buffer[pos] === 0xFF && buffer[pos + 1] !== 0xFF && buffer[pos + 1] !== 0x00) {
      const marker = buffer[pos + 1];

      if (marker === 0xD8) { // SOI
        segments.push({ type: 'SOI', start: pos, length: 2, marker });
        pos += 2;
      } else if (marker === 0xD9) { // EOI
        segments.push({ type: 'EOI', start: pos, length: 2, marker });
        break;
      } else if (marker === 0xDA) { // SOS - Start of Scan (image data follows)
        // Find the length of this segment
        const segmentLength = (buffer[pos + 2] << 8) | buffer[pos + 3];
        const headerEnd = pos + 2 + segmentLength;

        // Find the next marker after scan data
        let scanEnd = headerEnd;
        for (let i = headerEnd; i < buffer.length - 1; i++) {
          if (buffer[i] === 0xFF && buffer[i + 1] !== 0x00 && buffer[i + 1] >= 0xC0) {
            scanEnd = i;
            break;
          }
        }

        if (scanEnd === headerEnd) {
          scanEnd = buffer.length - 2; // If no marker found, assume it goes to EOI
        }

        segments.push({ 
          type: 'SOS', 
          start: pos, 
          length: scanEnd - pos, 
          marker,
          headerLength: segmentLength + 2,
          scanDataStart: headerEnd,
          scanDataLength: scanEnd - headerEnd
        });
        pos = scanEnd;
      } else if ((marker >= 0xC0 && marker <= 0xFE) && 
                 marker !== 0xD0 && marker !== 0xD1 && marker !== 0xD2 && 
                 marker !== 0xD3 && marker !== 0xD4 && marker !== 0xD5 && 
                 marker !== 0xD6 && marker !== 0xD7) {
        // Regular segment with length
        if (pos + 3 < buffer.length) {
          const segmentLength = (buffer[pos + 2] << 8) | buffer[pos + 3];
          segments.push({ 
            type: marker === 0xDB ? 'DQT' : marker === 0xC4 ? 'DHT' : `SEG_${marker.toString(16)}`,
            start: pos, 
            length: segmentLength + 2, 
            marker 
          });
          pos += segmentLength + 2;
        } else {
          pos++;
        }
      } else {
        pos++;
      }
    } else {
      pos++;
    }
  }

  // Build compressed JPEG
  let compressedParts = [];
  let currentSize = 0;

  for (const segment of segments) {
    const segmentData = buffer.slice(segment.start, segment.start + segment.length);

    if (segment.type === 'SOI' || segment.type === 'EOI') {
      // Always keep SOI and EOI
      compressedParts.push(segmentData);
      currentSize += segmentData.length;
    } else if (segment.type === 'DQT') {
      // Quantization table - gentle quality reduction
      let modifiedDQT = Buffer.from(segmentData);

      // Only modify quantization tables if we need significant compression
      const compressionRatio = targetBytes / buffer.length;
      if (compressionRatio < 0.7) {
        // Only increase quantization values by 20% for gentle compression
        for (let i = 5; i < modifiedDQT.length; i++) {
          const originalValue = modifiedDQT[i];
          modifiedDQT[i] = Math.min(255, Math.floor(originalValue * 1.2));
        }
      }
      // If less compression needed, keep original quantization tables

      compressedParts.push(modifiedDQT);
      currentSize += modifiedDQT.length;
    } else if (segment.type === 'SOS') {
      // Scan data - this is where we can save the most space
      const remainingBudget = targetBytes - currentSize - 2; // Reserve 2 bytes for EOI

      if (remainingBudget > segment.headerLength) {
        // Include the SOS header
        const sosHeader = segmentData.slice(0, segment.headerLength);
        compressedParts.push(sosHeader);
        currentSize += sosHeader.length;

        // Compress the scan data
        const availableForScanData = remainingBudget - segment.headerLength;
        const scanData = segmentData.slice(segment.headerLength);

        if (scanData.length > availableForScanData) {
          // More gentle scan data compression - take a higher percentage
          const compressionRatio = availableForScanData / scanData.length;
          let compressedScanData;

          if (compressionRatio > 0.8) {
            // If we only need to remove 20% or less, take from the end
            compressedScanData = scanData.slice(0, availableForScanData);
          } else {
            // For more compression needed, take chunks throughout the data
            compressedScanData = Buffer.alloc(availableForScanData);
            const step = scanData.length / availableForScanData;
            for (let i = 0; i < availableForScanData; i++) {
              const sourceIndex = Math.floor(i * step);
              compressedScanData[i] = scanData[sourceIndex];
            }
          }

          // Make sure we don't end on 0xFF (could create invalid marker)
          while (compressedScanData.length > 0 && compressedScanData[compressedScanData.length - 1] === 0xFF) {
            compressedScanData = compressedScanData.slice(0, -1);
          }

          compressedParts.push(compressedScanData);
          currentSize += compressedScanData.length;
        } else {
          compressedParts.push(scanData);
          currentSize += scanData.length;
        }
      }
      break; // Stop after processing scan data
    } else {
      // Other segments (DHT, SOF, etc.) - keep if we have budget
      const remainingBudget = targetBytes - currentSize;
      if (remainingBudget > segmentData.length) {
        compressedParts.push(segmentData);
        currentSize += segmentData.length;
      } else if (remainingBudget > 10) {
        // Keep partial segment if reasonable size
        compressedParts.push(segmentData.slice(0, remainingBudget));
        currentSize += remainingBudget;
      }
    }

    if (currentSize >= targetBytes - 10) break; // Leave room for EOI
  }

  // Ensure we end with EOI
  const eoi = Buffer.from([0xFF, 0xD9]);
  compressedParts.push(eoi);

  const result = Buffer.concat(compressedParts);
  console.log(`Compressed to ${(result.length/1024).toFixed(2)}KB`);

  return result;
}

// Main execution
try {
  // Validate JPEG format
  if (!validateJPEG(originalBuffer)) {
    return [{
      json: {
        error: "❌ Invalid JPEG format",
        message: "File does not appear to be a valid JPEG image",
        bufferSignature: originalBuffer.slice(0, 8).toString('hex').toUpperCase()
      }
    }];
  }

  const originalSizeKB = (originalBuffer.length / 1024).toFixed(2);
  console.log(`Processing JPEG image: ${originalSizeKB} KB`);

  // Compress image if needed
  let finalBuffer = originalBuffer;
  let wasCompressed = false;

  const targetSizeKB = 48; // Target 48KB to stay under 50KB with buffer

  if (originalBuffer.length > targetSizeKB * 1024) {
    finalBuffer = compressJPEG(originalBuffer, targetSizeKB);
    wasCompressed = true;
  }

  const finalSizeKB = (finalBuffer.length / 1024).toFixed(2);
  const base64Data = finalBuffer.toString('base64');
  const base64Length = base64Data.length;

  console.log(`Final image size: ${finalSizeKB} KB, Base64 length: ${base64Length} characters`);

  // Create data URI
  const dataUri = `data:image/jpeg;base64,${base64Data}`;

  // Final validation
  const meetsRequirement = finalBuffer.length <= 50 * 1024;

  return [{
    json: {
      message: wasCompressed ? 
        `✅ Successfully compressed JPEG from ${originalSizeKB}KB to ${finalSizeKB}KB` :
        `✅ JPEG processed (${finalSizeKB}KB - no compression needed)`,
      base64Data: base64Data,
      base64Length: base64Length,
      dataUri: dataUri,
      originalSize: originalBuffer.length,
      originalSizeKB: originalSizeKB,
      finalSize: finalBuffer.length,
      finalSizeKB: finalSizeKB,
      wasCompressed: wasCompressed,
      compressionRatio: wasCompressed ? 
        `${((1 - finalBuffer.length / originalBuffer.length) * 100).toFixed(1)}% reduction` : 
        'No compression applied',
      contentType: 'image/jpeg',
      fileExtension: 'jpg',
      meetsRequirement: meetsRequirement,
      requirementStatus: meetsRequirement ? 
        '✅ Under 50KB requirement' : 
        `⚠️ ${finalSizeKB}KB (still over 50KB - image may be too complex)`,
      compressionMethod: wasCompressed ? 'Gentle JPEG compression (minimal quality loss)' : 'None'
    }
  }];

} catch (error) {
  return [{
    json: {
      error: "❌ Failed to process JPEG image",
      message: error.message,
      details: error.toString(),
      debugInfo: {
        originalSize: originalBuffer ? originalBuffer.length : 'Unknown',
        errorType: error.constructor.name
      }
    }
  }];
}

// Function to properly escape SQL string values
function sanitizeSqlString(value) {
  if (value === null || value === undefined) {
    return '';
  }

  // Convert to string and escape single quotes by doubling them
  return String(value).replace(/'/g, "''");
}

