  if (!latest.Check_In_Date) return current;

  const latestDate = new Date(latest.Check_In_Date);
  const currentDate = new Date(current.Check_In_Date);
  return currentDate > latestDate ? current : latest;
});
// Extract document URLs from the most recent check-in
