    if (Array.isArray(contactsInput.json.contacts)) {
      contacts = contactsInput.json.contacts;
    }
  }
}

// Method 3: If still no contacts, check if it's a direct array
if (contacts.length === 0) {
  const contactsInput = allInputs[0];
  if (contactsInput && contactsInput.json) {
    if (Array.isArray(contactsInput.json)) {
      contacts = contactsInput.json;
    }
  }
}

// Method 4: Search through all inputs for contacts property
if (contacts.length === 0) {
  allInputs.forEach(input => {
    if (input.json && input.json.contacts && Array.isArray(input.json.contacts)) {
      contacts = input.json.contacts;
    }
  });
}

// Get guests - try all items from second input
let guests = [];
const guestsInputs = allInputs.slice(1);

guestsInputs.forEach(input => {
  if (input.json) {
    const data = input.json;
    if (Array.isArray(data)) {
      guests = guests.concat(data);
    } else {
      guests.push(data);
    }
  }
});

// Create guest phone map
const guestPhoneMap = new Map();
guests.forEach(guest => {
  const normalizedPhone = normalizePhone(guest.guestPhone);
  if (normalizedPhone) {
    guestPhoneMap.set(normalizedPhone, guest);
  }
});

// Process matches
const matchedContacts = [];
contacts.forEach(contact => {
  const normalizedContactPhone = normalizePhone(contact.phone);
  if (!normalizedContactPhone) return;

  const matchedGuest = guestPhoneMap.get(normalizedContactPhone);
  if (!matchedGuest) return;

  const within24Last_replied = contact.last_replied ? isWithin24Hours(contact.last_replied) : false;
  const within24Last_seen = contact.last_seen ? isWithin24Hours(contact.last_seen) : false;
  const within24Last_delivered = contact.last_delivered ? isWithin24Hours(contact.last_delivered) : false;

  const isActive = within24Last_replied || within24Last_seen || within24Last_delivered;

  if (isActive) {
    matchedContacts.push({
      phone: contact.phone,
      name: contact.name,
      guestName: matchedGuest.guestName,
      last_replied: contact.last_replied,
      last_seen: contact.last_seen,
      last_delivered: contact.last_delivered
    });
  }
});

// Return results or debug info
if (matchedContacts.length === 0) {
  return [{
    debug: {
      contactCount: contacts.length,
      guestCount: guests.length,
      sampleContact: contacts[0] || 'No contacts found',
      sampleGuest: guests[0] || 'No guests found',
      // Show first few contacts to help debug
      firstFewContacts: contacts.slice(0, 3).map(c => ({
        name: c.name,
        phone: c.phone,
        last_replied: c.last_replied,
        last_seen: c.last_seen,
        last_delivered: c.last_delivered
      })),
      // Show which guests we're trying to match
      guestPhones: guests.map(g => g.guestPhone).slice(0, 5),
      // Show any phone matches (even if not active)
      allMatches: contacts.filter(contact => {
        const normalizedContactPhone = normalizePhone(contact.phone);
        return normalizedContactPhone && guestPhoneMap.has(normalizedContactPhone);
      }).map(contact => ({
        phone: contact.phone,
        name: contact.name,
        last_replied: contact.last_replied,
        last_seen: contact.last_seen,
        last_delivered: contact.last_delivered,
        within24Hours: {
          replied: contact.last_replied ? isWithin24Hours(contact.last_replied) : false,
          seen: contact.last_seen ? isWithin24Hours(contact.last_seen) : false,
          delivered: contact.last_delivered ? isWithin24Hours(contact.last_delivered) : false
        }
      }))
    },
    message: 'No active matches found'
  }];
}

return matchedContacts;

