        /(?:Father\'?s?\s*Name|पिता का नाम)[\/\s]*[:\s]*([A-Z][A-Z\s]+?)(?=\s+(?:Address|Age|Gender|Constituency|Assembly|पता|उम्र))/i,
        // "Husband's Name / पति का नाम : NAME"
        /(?:Husband\'?s?\s*Name|पति का नाम)[\/\s]*[:\s]*([A-Z][A-Z\s]+?)(?=\s+(?:Address|Age|Gender|Constituency|Assembly|पता|उम्र))/i,
        // Simplified patterns
        /(?:Father|Husband|पिता|पति)[:\s]*([A-Za-z\s]+?)(?=\n|Address|Age|Gender|Constituency)/i,
        // Pattern with "S/O" (Son of) or "W/O" (Wife of)
        /(?:S\/O|W\/O|D\/O)[:\s]*([A-Z][A-Z\s]+?)(?=\s+(?:Address|Age|Gender|Assembly))/i
      ]);

      // Voter ID number - EPIC format (3 letters + 7 digits)
      const voterMatch = text.match(/(?:EPIC No|Elector\'?s?\s*Photo Identity Card|Electoral Photo Identity Card|मतदाता पहचान पत्र)[\/\s]*[:\s]*([A-Z]{3}\d{7})/i) ||
                        text.match(/(?:Card No|Identity No|ID No)[:\s]*([A-Z]{3}\d{7})/i) ||
                        text.match(/\b([A-Z]{3}\d{7})\b/) ||
                        text.match(/([A-Z]{3}\d{7})/);
      if (voterMatch) {
        info.documentNumber = voterMatch[1];
      }

      // Age and Date of Birth for Voter ID
      const ageMatch = text.match(/(?:Age|उम्र)[\/\s]*[:\s]*(\d{1,3})/i) ||
                      text.match(/(\d{2,3})(?=\s+(?:Male|Female|M|F|Years))/i);
      const dobMatch = text.match(/(?:Date of Birth|जन्म तारीख)[\/\s]*[:\s]*(\d{1,2}[\/\-]\d{1,2}[\/\-]\d{4})/i) ||
                      text.match(/(?:DOB)[:\s]*(\d{1,2}[\/\-]\d{1,2}[\/\-]\d{4})/i);

      if (dobMatch) {
        info.dateOfBirth = dobMatch[1];
      } else if (ageMatch) {
        // Calculate approximate birth year from age
        const currentYear = new Date().getFullYear();
        const birthYear = currentYear - parseInt(ageMatch[1]);
        info.dateOfBirth = `01/01/${birthYear}`;
      }

      // Assembly Constituency for Voter ID
      const constituencyMatch = text.match(/(?:Assembly Constituency|Constituency|निर्वाचन क्षेत्र|विधानसभा क्षेत्र)[\/\s]*[:\s]*([A-Za-z0-9\s\-]+?)(?=\s+(?:Part|Serial|Address|पता))/i) ||
                              text.match(/(?:AC|A\.C\.)[:\s]*([A-Za-z0-9\s\-]+?)(?=\s+(?:Part|Serial))/i);
      if (constituencyMatch) {
        info.constituency = cleanText(constituencyMatch[1]);
      }

      // Part Number and Serial Number
      const partMatch = text.match(/(?:Part No|Part Number)[\/\s]*[:\s]*(\d+)/i);
      const serialMatch = text.match(/(?:Serial No|Serial Number|Sl\. No)[\/\s]*[:\s]*(\d+)/i);

      // Address for Voter ID
      const addressMatch = text.match(/(?:Address|पता)[\/\s]*[:\s]*([^A-Z]*?)(?=Election Commission|EPIC|Issued|Part No|Serial No|$)/i) ||
                          text.match(/(?:Address|पता)[:\s]*([^।]*?)(?=Election Commission|निर्वाचन आयोग|$)/i);
      if (addressMatch) {
