        last_replied: c.last_replied,
        last_seen: c.last_seen,
        last_delivered: c.last_delivered
      })),
      // Show which guests we're trying to match
      guestPhones: guests.map(g => g.guestPhone).slice(0, 5),
      // Show any phone matches (even if not active)
      allMatches: contacts.filter(contact => {
        const normalizedContactPhone = normalizePhone(contact.phone);
        return normalizedContactPhone && guestPhoneMap.has(normalizedContactPhone);
      }).map(contact => ({
        phone: contact.phone,
        name: contact.name,
        last_replied: contact.last_replied,
        last_seen: contact.last_seen,
        last_delivered: contact.last_delivered,
        within24Hours: {
