    urlMap.set(msg.url, msg);
  }
});

const uniqueMessages = Array.from(urlMap.values());

console.log('Total after deduplication:', uniqueMessages.length);

// Sort: SQL documents by Upload_Date first, then Code16 documents
uniqueMessages.sort((a, b) => {
  // If both have upload_date, sort by date
  if (a.upload_date && b.upload_date) {
    return new Date(a.upload_date) - new Date(b.upload_date);
  }
  // If only a has upload_date, it comes first
  if (a.upload_date && !b.upload_date) return -1;
  // If only b has upload_date, it comes first
  if (!a.upload_date && b.upload_date) return 1;
  // If neither has upload_date, maintain order
  return 0;
});

// Add sequence numbers
const messages = uniqueMessages.map((msg, index) => {
  const result = {
    message: msg.message,
    phone: msg.phone,
    business_phone_number_id: msg.business_phone_number_id,
    access_token: msg.access_token,
    tenant_id: msg.tenant_id,
    custom: msg.custom,
    sequence: index + 1,
    total: uniqueMessages.length
  };

  if (msg.upload_date) {
    result.upload_date = msg.upload_date;
  }

  return result;
});

console.log('Final messages to send:', messages.length);
console.log('Order: SQL docs (oldest first), then Code16 docs');

return messages;
